const { Gmail } = require('gog');
const fs = require('fs');
const path = require('path');

async function runSweep() {
  const g = new Gmail();
  const memoryDir = '/Users/louishyman/.openclaw/workspaces/maxwell-workspace/memory';
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const latestFile = path.join(memoryDir, 'gmail-intake-latest.json');
  const sweepFile = path.join(memoryDir, `gmail-sweep-${timestamp}.json`);

  const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

  // Fetch threads
  // Note: gog/Gmail implementation might vary; assuming standard search-based retrieval
  // We use 'newer_than:1d' as a proxy for last 24h
  const threads = await g.threads.list({ q: 'newer_than:1d' });
  const selectedThreads = threads.messages.slice(0, 20);

  const processedThreads = [];
  const counts = { urgent: 0, today: 0, this_week: 0, fyi: 0, spam_or_noise: 0 };
  let threads_scanned = 0;

  for (const thread of selectedThreads) {
    threads_scanned++;
    const msg = await g.threads.get({ id: thread.id });
    const subject = msg.snippet || '';
    const dateStr = msg.internalDate; // Assuming timestamp format
    const msgDate = new Date(parseInt(dateStr));

    // Classification logic
    let classification = 'fyi';
    const now = new Date();
    const diffDays = (now - msgDate) / (1000 * 60 * 60 * 24);

    // Simple heuristic: if subject contains 'urgent' or '!!!'
    if (/urgent|action required|immediate/i.test(subject)) {
      classification = 'urgent';
    } else if (diffDays < 1) {
      classification = 'today';
    } else if (diffDays < 7) {
      classification = 'this_week';
    } else if (/newsletter|promo|unsubscribe|advertisement/i.test(subject)) {
      classification = 'spam_or_noise';
    }

    counts[classification]++;
    processedThreads.push({
      id: thread.id,
      subject: subject,
      date: msgDate.toISOString(),
      classification
    });
  }

  const result = {
    timestamp: new Date().toISOString(),
    threads_scanned,
    counts,
    threads: processedThreads
  };

  fs.writeFileSync(latestFile, JSON.stringify(result, null, 2));
  fs.writeFileSync(sweepFile, JSON.stringify(result, null, 2));

  console.log(`Summary: urgent:${counts.urgent}, today:${counts.today}, this_week:${counts.this_week}, fyi:${counts.fyi}, spam_or_noise:${counts.spam_or_noise}, threads_scanned:${threads_scanned}`);
}

runSweep().catch(err => {
  console.error(err);
  process.exit(1);
});
