const { Gmail } = require('gog');
const fs = require('fs');
const path = require('path');

async function runSweep() {
  const g = new Gmail();
  const memoryDir = '/Users/louishyman/.openclaw/workspaces/maxwell-workspace/memory';
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const latestFile = path.join(memoryDir, 'gmail-intake-latest.json');
  const sweepFile = path.join(memoryDir, `gmail-sweep-${timestamp}.json`);

  const counts = { urgent: 0, today: 0, this_week: 0, fyi: 0, spam_or_noise: 0 };
  let threads_scanned = 0;
  const processedThreads = [];

  try {
    const response = await g.threads.list({ q: 'newer_than:1d' });
    const threads = (response.messages || response.threads || []);
    const selectedThreads = threads.slice(0, 20);

    for (const thread of selectedThreads) {
      threads_scanned++;
      const threadId = thread.id || thread.messageId;
      const msg = await g.threads.get({ id: threadId });
      const subject = msg.snippet || '';
      const msgDate = new Date(parseInt(msg.internalDate));

      let classification = 'fyi';
      const now = new Date();
      const diffDays = (now - msgDate) / (1000 * 60 * 60 * 24);

      if (/urgent|action required|immediate/i.test(subject)) {
        classification = 'urgent';
      } else if (diffDays < 1) {
        classification = 'today';
      } else if (diffDays < 7) {
        classification = 'this_week';
      } else if (/newsletter|promo|unsubscribe|advertisement/i.test(subject)) {
        classification = 'spam_or_noise';
      }

      counts[classification]++;
      processedThreads.push({
        id: threadId,
        subject: subject,
        date: msgDate.toISOString(),
        classification
      });
    }

    const result = {
      timestamp: new Date().toISOString(),
      threads_scanned,
      counts,
      threads: processedThreads
    };

    if (!fs.existsSync(memoryDir)) fs.mkdirSync(memoryDir, { recursive: true });
    fs.writeFileSync(latestFile, JSON.stringify(result, null, 2));
    fs.writeFileSync(sweepFile, JSON.stringify(result, null, 2));

    process.stdout.write(`Summary: urgent:${counts.urgent}, today:${counts.today}, this_week:${counts.this_week}, fyi:${counts.fyi}, spam_or_noise:${counts.spam_or_noise}, threads_scanned:${threads_scanned}\n`);
  } catch (err) {
    console.error(err);
    process.exit(1);
  }
}

